(function () {
  "use strict";

  // ---- Configuration ----
  // Set this via a data attribute on the script tag, e.g.:
  // <script src="ava-widget.js" data-backend="https://your-backend.vercel.app/api/chat"><\/script>
  var scriptTag = document.currentScript;
  var BACKEND_URL = (scriptTag && scriptTag.getAttribute("data-backend")) || "/api/chat";

  var LOGO_SRC = "data:image/png;base64,";

  var GREETING = "Hi! I'm AVA \u2708\ufe0f\ud83c\udf0e\nI'm the All Access Virtual Advisor and I'm here to help you dream, explore, and discover travel experiences designed around YOU.\nCruise curious? \ud83d\udee2\ufe0f\nPlanning with accessibility needs in mind? \u267f\nDreaming about a bucket-list adventure? \ud83c\udf0e\nOr simply have no idea where you want to go yet? That's okay too!\nTell me\u2026\n\u2728 If you could travel anywhere tomorrow, where would you go?\nIf you can dream it, we can plan it! \ud83e\udde1\ud83d\udc99";

  var SUGGESTIONS = [
    "Best all-inclusive spot for a honeymoon?",
    "Family trip under $4k, where should we go?",
    "What's the best time to visit Italy?",
    "First-time cruise \u2014 what should I know?"
  ];

  // ---- Styles ----
  var css = "\n" +
    ".ava-launcher{position:fixed;bottom:24px;right:24px;width:64px;height:64px;border-radius:50%;background:#0B3D4E;border:3px solid #FBF3E8;box-shadow:0 10px 30px -8px rgba(11,61,78,0.5);cursor:pointer;z-index:999998;overflow:hidden;padding:0;transition:transform .15s ease;}\n" +
    ".ava-launcher:hover{transform:scale(1.06);}\n" +
    ".ava-launcher img{width:100%;height:100%;object-fit:cover;display:block;}\n" +
    ".ava-launcher .ava-close-icon{display:none;}\n" +
    ".ava-launcher.open .ava-logo{display:none;}\n" +
    ".ava-launcher.open .ava-close-icon{display:flex;align-items:center;justify-content:center;width:100%;height:100%;color:#FBF3E8;font-size:26px;font-family:Arial,sans-serif;}\n" +
    ".ava-panel{position:fixed;bottom:100px;right:24px;width:380px;max-width:calc(100vw - 32px);height:600px;max-height:calc(100vh - 140px);background:#FBF3E8;border-radius:20px;box-shadow:0 20px 50px -20px rgba(11,61,78,0.45);z-index:999999;display:none;flex-direction:column;overflow:hidden;font-family:Inter,Arial,sans-serif;}\n" +
    ".ava-panel.open{display:flex;}\n" +
    ".ava-header{padding:18px 20px 16px;background:linear-gradient(180deg,#0B3D4E 0%,#133F52 100%);color:#FBF3E8;flex-shrink:0;position:relative;}\n" +
    ".ava-header-top{display:flex;align-items:center;gap:12px;}\n" +
    ".ava-header-avatar{width:42px;height:42px;border-radius:50%;overflow:hidden;flex-shrink:0;border:2px solid rgba(251,243,232,0.85);}\n" +
    ".ava-header-avatar img{width:100%;height:100%;object-fit:cover;display:block;}\n" +
    ".ava-title{font-weight:600;font-size:16px;line-height:1.2;}\n" +
    ".ava-subtitle{font-size:12px;opacity:.72;margin-top:2px;}\n" +
    ".ava-header-close{position:absolute;top:14px;right:16px;background:none;border:none;color:#FBF3E8;font-size:20px;cursor:pointer;opacity:.8;line-height:1;padding:4px;}\n" +
    ".ava-header-close:hover{opacity:1;}\n" +
    ".ava-horizon{margin-top:14px;height:3px;border-radius:3px;background:linear-gradient(90deg,#0B3D4E,#6FB8B0,#F2A65A,#E8785A,#0B3D4E);background-size:300% 100%;animation:avaDrift 14s linear infinite;}\n" +
    "@keyframes avaDrift{0%{background-position:0% 50%;}100%{background-position:300% 50%;}}\n" +
    ".ava-messages{flex:1;overflow-y:auto;padding:18px;display:flex;flex-direction:column;gap:12px;background:#FBF3E8;}\n" +
    ".ava-row{display:flex;}\n" +
    ".ava-row.user{justify-content:flex-end;}\n" +
    ".ava-row.agent{justify-content:flex-start;}\n" +
    ".ava-bubble{max-width:84%;padding:10px 14px;border-radius:16px;font-size:14px;line-height:1.5;white-space:pre-wrap;}\n" +
    ".ava-bubble.agent{background:#fff;border:1px solid rgba(11,61,78,0.1);border-bottom-left-radius:4px;color:#12262C;}\n" +
    ".ava-bubble.user{background:linear-gradient(135deg,#1C7293,#0B3D4E);color:#FBF3E8;border-bottom-right-radius:4px;}\n" +
    ".ava-label{display:flex;align-items:center;gap:6px;font-size:11px;font-weight:600;color:#E8785A;margin-bottom:4px;letter-spacing:.3px;}\n" +
    ".ava-mini-avatar{width:16px;height:16px;border-radius:50%;overflow:hidden;flex-shrink:0;}\n" +
    ".ava-mini-avatar img{width:100%;height:100%;object-fit:cover;display:block;}\n" +
    ".ava-dots{display:flex;gap:4px;padding:4px 2px;}\n" +
    ".ava-dots span{width:6px;height:6px;border-radius:50%;background:#1C7293;opacity:.4;animation:avaBounce 1.2s infinite ease-in-out;}\n" +
    ".ava-dots span:nth-child(2){animation-delay:.15s;}\n" +
    ".ava-dots span:nth-child(3){animation-delay:.3s;}\n" +
    "@keyframes avaBounce{0%,60%,100%{transform:translateY(0);opacity:.4;}30%{transform:translateY(-4px);opacity:1;}}\n" +
    ".ava-suggestions{display:flex;flex-wrap:wrap;gap:8px;padding:0 18px 12px;flex-shrink:0;}\n" +
    ".ava-chip{font-size:12px;padding:6px 12px;border-radius:999px;background:#fff;border:1px solid rgba(11,61,78,0.15);color:#0B3D4E;cursor:pointer;}\n" +
    ".ava-chip:hover{background:#F2A65A;border-color:#F2A65A;color:#12262C;}\n" +
    ".ava-input-row{display:flex;gap:8px;padding:12px 14px;border-top:1px solid rgba(11,61,78,0.1);background:#fff;flex-shrink:0;}\n" +
    ".ava-input{flex:1;border:1px solid rgba(11,61,78,0.18);border-radius:12px;padding:10px 12px;font-size:14px;resize:none;outline:none;color:#12262C;font-family:inherit;}\n" +
    ".ava-input:focus{border-color:#1C7293;}\n" +
    ".ava-send{background:linear-gradient(135deg,#E8785A,#F2A65A);border:none;border-radius:12px;width:42px;flex-shrink:0;color:#12262C;font-size:16px;cursor:pointer;}\n" +
    ".ava-send:disabled{opacity:.5;cursor:not-allowed;}\n" +
    "@media (max-width:480px){.ava-panel{right:12px;left:12px;width:auto;bottom:92px;}.ava-launcher{right:16px;bottom:16px;}}\n";

  var styleEl = document.createElement("style");
  styleEl.textContent = css;
  document.head.appendChild(styleEl);

  // ---- Markup ----
  var launcher = document.createElement("button");
  launcher.className = "ava-launcher";
  launcher.setAttribute("aria-label", "Open AVA, the All Access Travels virtual advisor");
  launcher.innerHTML = "<img class=\"ava-logo\" src=\"" + LOGO_SRC + "\" alt=\"\" /><span class=\"ava-close-icon\">\u2715</span>";

  var panel = document.createElement("div");
  panel.className = "ava-panel";
  panel.innerHTML =
    "<div class=\"ava-header\">" +
      "<button class=\"ava-header-close\" aria-label=\"Close chat\">\u2715</button>" +
      "<div class=\"ava-header-top\">" +
        "<div class=\"ava-header-avatar\"><img src=\"" + LOGO_SRC + "\" alt=\"All Access Travels logo\" /></div>" +
        "<div><div class=\"ava-title\">AVA</div><div class=\"ava-subtitle\">All Access Virtual Advisor \u00b7 All Access Travels</div></div>" +
      "</div>" +
      "<div class=\"ava-horizon\"></div>" +
    "</div>" +
    "<div class=\"ava-messages\"></div>" +
    "<div class=\"ava-suggestions\"></div>" +
    "<div class=\"ava-input-row\">" +
      "<textarea class=\"ava-input\" rows=\"1\" placeholder=\"Ask about a destination or trip idea...\"></textarea>" +
      "<button class=\"ava-send\" aria-label=\"Send message\">\u27a4</button>" +
    "</div>";

  document.body.appendChild(launcher);
  document.body.appendChild(panel);

  var messagesEl = panel.querySelector(".ava-messages");
  var suggestionsEl = panel.querySelector(".ava-suggestions");
  var inputEl = panel.querySelector(".ava-input");
  var sendBtn = panel.querySelector(".ava-send");
  var closeBtn = panel.querySelector(".ava-header-close");

  var history = [];
  var loading = false;

  function scrollToBottom() {
    messagesEl.scrollTop = messagesEl.scrollHeight;
  }

  function renderMessage(role, content) {
    var row = document.createElement("div");
    row.className = "ava-row " + (role === "user" ? "user" : "agent");

    var wrap = document.createElement("div");

    if (role !== "user") {
      var label = document.createElement("div");
      label.className = "ava-label";
      label.innerHTML = "<span class=\"ava-mini-avatar\"><img src=\"" + LOGO_SRC + "\" alt=\"\" /></span>AVA";
      wrap.appendChild(label);
    }

    var bubble = document.createElement("div");
    bubble.className = "ava-bubble " + (role === "user" ? "user" : "agent");
    bubble.textContent = content;
    wrap.appendChild(bubble);

    row.appendChild(wrap);
    messagesEl.appendChild(row);
    scrollToBottom();
  }

  var typingRow = null;
  function showTyping() {
    typingRow = document.createElement("div");
    typingRow.className = "ava-row agent";
    typingRow.innerHTML =
      "<div>" +
        "<div class=\"ava-label\"><span class=\"ava-mini-avatar\"><img src=\"" + LOGO_SRC + "\" alt=\"\" /></span>AVA</div>" +
        "<div class=\"ava-bubble agent\"><div class=\"ava-dots\"><span></span><span></span><span></span></div></div>" +
      "</div>";
    messagesEl.appendChild(typingRow);
    scrollToBottom();
  }
  function hideTyping() {
    if (typingRow) { typingRow.remove(); typingRow = null; }
  }

  function renderSuggestions() {
    suggestionsEl.innerHTML = "";
    SUGGESTIONS.forEach(function (s) {
      var chip = document.createElement("div");
      chip.className = "ava-chip";
      chip.textContent = s;
      chip.addEventListener("click", function () { sendMessage(s); });
      suggestionsEl.appendChild(chip);
    });
  }

  function sendMessage(text) {
    var content = (text !== undefined ? text : inputEl.value).trim();
    if (!content || loading) return;

    renderMessage("user", content);
    history.push({ role: "user", content: content });
    inputEl.value = "";
    suggestionsEl.innerHTML = "";
    loading = true;
    sendBtn.disabled = true;
    showTyping();

    fetch(BACKEND_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ messages: history })
    })
      .then(function (r) { return r.json(); })
      .then(function (data) {
        hideTyping();
        var reply = data.reply || "Sorry, I did not quite catch that \u2014 could you try asking again?";
        renderMessage("assistant", reply);
        history.push({ role: "assistant", content: reply });
      })
      .catch(function () {
        hideTyping();
        renderMessage("assistant", "I am having trouble connecting right now. Mind trying again in a moment?");
      })
      .finally(function () {
        loading = false;
        sendBtn.disabled = false;
      });
  }

  sendBtn.addEventListener("click", function () { sendMessage(); });
  inputEl.addEventListener("keydown", function (e) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  });

  function openPanel() {
    panel.classList.add("open");
    launcher.classList.add("open");
    launcher.setAttribute("aria-label", "Close AVA chat");
    inputEl.focus();
  }
  function closePanel() {
    panel.classList.remove("open");
    launcher.classList.remove("open");
    launcher.setAttribute("aria-label", "Open AVA, the All Access Travels virtual advisor");
  }

  launcher.addEventListener("click", function () {
    if (panel.classList.contains("open")) { closePanel(); } else { openPanel(); }
  });
  closeBtn.addEventListener("click", closePanel);

  renderMessage("assistant", GREETING);
  renderSuggestions();
})();
